" CDS - ideal for Fiori OData reporting
@OData.publish: true
@Analytics.dataCategory: #CUBE
define view ZC_SALES_KPI as
  select from ZI_SALES_BY_REGION
  {
    SalesOrg, OrderDate,
    sum(TotalValue) as Revenue
  }
  group by SalesOrg, OrderDate;

" CDS Table Function definition
define table function ZTF_FISCAL_PERIODS
  with parameters
    p_year : gjahr
  returns {
    period  : poper;
    start_d : dats;
    end_d   : dats;
  }
  implemented by method
    ZCL_FISCAL_AMDP=>GET_PERIODS;

" Implementing AMDP class method
METHOD get_periods
    BY DATABASE FUNCTION FOR HDB  " note: FUNCTION not PROCEDURE
    LANGUAGE SQLSCRIPT OPTIONS READ-ONLY
    USING t009b.
  " Note: T009B has BUMON/BUTAG/BDATJ for period boundaries — not BUDAT
  et_result = SELECT monat AS period,
               bumon AS start_d, bumon AS end_d
             FROM t009b WHERE gjahr = :p_year;
ENDMETHOD.

@AccessControl.authorizationCheck: #CHECK
define view ZI_SALES_SECURE as
  select from vbak { vbeln, vkorg, kunnr };

" DCL file: ZI_SALES_SECURE.dcl
accesspolicy ZI_SALES_SECURE {
  grant select on ZI_SALES_SECURE
  where (vkorg) = aspect pfcg_auth(V_VBAK_VKO, VKORG, ACTVT='03');
};
" Result: each user auto-filtered to their allowed sales orgs

METHOD scalar_and_tabular
    BY DATABASE PROCEDURE FOR HDB
    LANGUAGE SQLSCRIPT OPTIONS READ-ONLY
    USING vbak.
  -- Scalar variable with DECLARE
  DECLARE lv_year NVARCHAR(4) := '2024';
  DECLARE lv_count INT := 0;
  -- Tabular variable - no DECLARE, direct assignment
  lt_orders = SELECT vbeln, kunnr
              FROM vbak
              WHERE erdat LIKE :lv_year || '%';
  SELECT COUNT(*) INTO lv_count FROM :lt_orders;
  -- Use scalar in output
  et_result = SELECT :lv_count AS total_orders,
                     kunnr FROM :lt_orders;
ENDMETHOD.
